var __index = {"config":{"lang":["en"],"separator":"[\\s\\-]+","pipeline":["stopWordFilter"],"fields":{"title":{"boost":1000.0},"text":{"boost":1.0},"tags":{"boost":1000000.0}}},"docs":[{"location":"index.html","title":"Recipes","text":"<p>\ud83d\udd17 Online Version: estherloeliger.github.io/recipes</p> <p>\ud83d\udc19 GitHub Repository: github.com/estherloeliger/recipes</p>"},{"location":"big_meals/bolognese.html","title":"\ud83c\udf5d Bolognese","text":""},{"location":"big_meals/bolognese.html#ingredients","title":"\ud83d\uded2 Ingredients","text":"<p>1 Tbsp olive oil 500g (red) onions, finely minced 6 cloves of garlic 120g celery, finely minced  120g carrots, finely minced 120g optional: courgette / red pepper, finely minced 1 tsp olive oil  400g mushrooms, finely minced 750g soya mince (frozen, Linda McCartney) 1 Tbs yeast extract 2 Tbs soya sauce / tamari 2 tsp (smoked) salt 4 tins chopped tomatoes 1 bay leave 2 Tbs tomato pur\u00e9e  1 Tbsp sugar 1(?) tsp salt (season to taste w salt after cooking)</p>"},{"location":"big_meals/bolognese.html#method","title":"\ud83d\udc68\u200d\ud83c\udf73 Method","text":"<p>Fry onions in olive oil until ever so slightly browned. Add garlic for 1 minute in the end. Fry veggies for 3 minutes. Transfer to slow cooker. Add the tsp of olive oil then fry mushrooms until all water has evaporated. Add soya mince and continue frying until defrosted and slightly fried. Season with yeast extract, soya sauce and smoked salt. Mix thoroughly. Transfer to the slow cooker. Pour tinned tomatoes in the pot used for frying and mash with a masher before adding them to the slow cooker. Add tomato pur\u00e9e and sugar, mix thoroughly. Hide bay leave near the centre.</p> <p>Cook on high for 5h.</p> <p>Season with salt / black pepper to taste after cooking.</p>"},{"location":"big_meals/cajun-kidney-beans.html","title":"Cajun kidney beans","text":""},{"location":"big_meals/cajun-kidney-beans.html#ingredients","title":"Ingredients","text":"<p>1Tbs oil 400g minced red onions 30g minced garlic 2 Tbs Cajun spice mix (M&amp;S) 400g finely minced green peppers 400g finely minced celery (peeled on the outside) 10 tins Kidney beans (drained and rinsed) 2 bay leaves 450ml veg broth 3.5 tsp smoked salt / salt 2 tsp dark brown sugar 3 Tbs lime juice</p>"},{"location":"big_meals/cajun-kidney-beans.html#method","title":"Method","text":"<ul> <li>Fry onions until browned</li> <li>Add garlic and spices and fry some more</li> <li>Add everything to the slow cooker cook on high (hours) or on low (hours)</li> <li>Mash about half the kidney beans, just inside the slow cooker.</li> </ul>"},{"location":"big_meals/chinese-chicken.html","title":"Chinese chicken","text":""},{"location":"big_meals/chinese-chicken.html#ingredients","title":"Ingredients","text":"<ul> <li>2 chicken breasts</li> <li>1 piece ginger</li> <li>3tbsp cooking wine</li> <li>2tbsp light soy sauce</li> <li>1 egg</li> <li>6tbsp cornstarch</li> <li>1 bunchof green onions</li> <li>Oil for frying</li> </ul>"},{"location":"big_meals/chinese-chicken.html#sauce","title":"Sauce:","text":"<ul> <li>2 tbsp light soy sauce</li> <li>1 tbsp darkk soy sauce</li> <li>1/2 tbsp sugar</li> <li>1/2 tsp Chinese five spice</li> <li>A little chicken powder</li> <li>1.5 cups water</li> </ul>"},{"location":"big_meals/chinese-chicken.html#steps","title":"Steps","text":"<ul> <li>Slice chicken breast into thick pieces and pound lightly with a meat mallet.</li> <li>Smash ginger and mix with cooking wine. Massage the ginger wine and soy sauce into the chicken for about 1 minute.</li> <li>Add egg and cornstarch. Mix until evenly coated.</li> <li>Pen-fry chicken over medium heat until golden on both sides. Remove and set aside.</li> <li>In the same pan, fry ginger and scalion whites for about 1 minute.</li> <li>Lay the scallion greens underneath, then place the chicken on top.</li> <li>Pour in the sauce and water. Bring to a boil.</li> <li>Cover and simmer over medium-low heat for 10 minutes.</li> <li>Remove the lid and reduce the sauce until glossy.</li> </ul>"},{"location":"big_meals/italian-tofu-meatballs.html","title":"Italian tofu meatballs","text":""},{"location":"big_meals/italian-tofu-meatballs.html#preparation-time","title":"Preparation time","text":"<p>30 minutes</p>"},{"location":"big_meals/italian-tofu-meatballs.html#ingredients","title":"Ingredients","text":"<p>1 (14 ounce) package extra-firm tofu</p> <p>1 onion, chopped</p> <p>1 egg</p> <p>\u00bd cup bread crumbs</p> <p>\u00bd cup grated Parmesan cheese</p> <p>1 tablespoon Worcestershire sauce</p> <p>1 \u00bc teaspoons chopped fresh basil</p> <p>1 \u00bc teaspoons chopped fresh marjoram</p> <p>1 \u00bc teaspoons chopped fresh rosemary</p> <p>1 \u00bc teaspoons chopped fresh oregano</p> <p>1 \u00bc teaspoons chopped fresh thyme</p> <p>1 teaspoon red pepper flakes</p> <p>1 teaspoon salt</p> <p>\u00bd teaspoon hot sauce</p> <p>\u00bd teaspoon minced garlic</p> <p>\u00bc cup olive oil</p>"},{"location":"big_meals/italian-tofu-meatballs.html#method","title":"Method","text":"<p>Preheat oven to 400 degrees F (200 degrees C). Line a baking sheet with aluminum foil.</p> <p>Place tofu onto a plate and place another plate on top. Set a 3- to 5-pound weight on top. Press tofu for 15 minutes to drain excess water. Break tofu into small pieces and squeeze again to remove as much water as possible.</p> <p>Place tofu in a large bowl. Add onion, egg, bread crumbs, Parmesan cheese, Worcestershire sauce, basil, marjoram, rosemary, oregano, thyme, red pepper flakes, salt, hot sauce, and garlic; mix well with your hands until thoroughly combined.</p> <p>Drizzle some olive oil on the lined baking sheet. Form tablespoonfuls of tofu mixture into balls and arrange in rows on the baking sheet. Drizzle remaining olive oil over meatballs.</p> <p>Bake in the preheated oven until browned and firm to the touch, 25 to 30 minutes.</p>"},{"location":"big_meals/japanese-chicken-meatballs.html","title":"Japanese chicken meatballs","text":"<p>Note</p> <p>test</p>"},{"location":"big_meals/japanese-chicken-meatballs.html#ingredients","title":"Ingredients","text":"<ul> <li>2 tbsp soy sauce</li> <li>2 tbsp mirin</li> <li>2 tbsp sake</li> <li>1 tbsp sugar</li> </ul> <p>Optional: * Sesame seeds</p>"},{"location":"big_meals/japanese-chicken-meatballs.html#instructions","title":"Instructions","text":"<ul> <li> <p>Season the ground chicken with salt and pepper</p> </li> <li> <p>Add chopped green onion, grated ginger, egg and potato starch. Mix well until combined.</p> </li> <li> <p>Shape into meatballs.</p> </li> <li> <p>Cook in a lightly oiled pan until browned on both sides.</p> </li> </ul> <p>Optionsl: cover the pan with a lid for a few minutes for extra juicy and fluffy tsukune.</p> <ul> <li> <p>Pour in the sauce and simmer until glossy and coated.</p> </li> <li> <p>Sprinkle with sesame seeds and enjoy.</p> </li> </ul>"},{"location":"big_meals/shredded-chicken.html","title":"Slow cooker shredded chicken","text":""},{"location":"big_meals/shredded-chicken.html#key-ingredients","title":"Key ingredients","text":"<ul> <li>Chicken breasts: You\u2019ll need 2 pounds of boneless, skinless chicken breasts (about 4 chicken breasts).</li> <li>Chicken stock, low-sodium chicken broth, or water: I prefer chicken stock or low-sodium chicken broth if I have it on hand because it adds a little more flavor, but water works equally well. Adding some liquid to the slow cooker is an essential step, and ensures that the chicken is tender and juicy.</li> </ul>"},{"location":"big_meals/shredded-chicken.html#instructions","title":"Instructions","text":"<ul> <li>Add the ingredients to the slow cooker. Place the chicken and stock, broth, or water in a 4-quart or larger slow cooker.</li> <li>Cook the chicken. Cover and cook until the chicken is tender and registers an internal temperature of 165\u00b0F, 4 to 5 hours on the LOW setting, or 2 to 3 hours on the HIGH setting.</li> <li>Shred the chicken. Transfer the meat to a plate or cutting board and use two forks to pull it apart. The chicken will be so soft and tender that it will practically fall apart with just a little prodding.</li> </ul>"},{"location":"big_meals/shredded-chicken.html#helpful-tips","title":"Helpful tips","text":"<ul> <li> <p>How to scale the recipe up or down: Whether you\u2019re making just a few servings or enough to feed a crowd, the effort remains the same. The important thing to remember is keeping the right ratio of chicken to liquid, which is 1/2 cup of chicken stock, low-sodium chicken broth, or water for every pound of chicken.</p> </li> <li> <p>The best way to shred chicken: While this technique is super simple, the chicken doesn\u2019t actually fall apart into shreds on its own (wouldn\u2019t that be nice!). The most important thing to know is that it\u2019s best to shred the chicken when it\u2019s still warm, preferably right after it\u2019s done cooking. As the chicken cools, the muscle fibers start to tighten up, which makes it a little tougher to shred. It\u2019s not impossible and it still works, but it takes some more effort and the meat tends to pull apart in larger chunks rather than thin, wispy shreds.</p> </li> <li> <p>Ways to use shredded chicken: The chicken will absorb cooking liquid while you shred, keeping it tender for chicken tacos, chicken salads, chicken casseroles, and more.</p> </li> </ul>"},{"location":"big_meals/shredded-chicken.html#storage-tips","title":"Storage tips","text":"<p>Refrigerate the shredded chicken in an airtight container for up to 4 days or in the freezer for up to 4 months.</p>"},{"location":"big_meals/soya-burgers.html","title":"Soya burgers","text":""},{"location":"big_meals/soya-burgers.html#ingredients","title":"Ingredients","text":"<p>210g soya mince, finely minced (eg Linda McCartney frozen) * 70g onions, finely minced almost pur\u00e9ed  1 tsp garlic, finely minced almost pur\u00e9ed 1 tsp Dijon mustard 1 tsp ketchup / tomato pur\u00e9e  2 Tbs flat leaved parsley, finely minced 1.5 Tbs chickpea flower **</p> <p>* (try adding finely minced and fried mushrooms) ** (try poha thick rice flakes instead or a mix)</p>"},{"location":"big_meals/soya-burgers.html#method","title":"Method","text":"<p>Mix all ingredients, form patties and let them cool in the fridge.</p>"},{"location":"big_meals/stamina-stirfry.html","title":"Stamina stir-fry","text":""},{"location":"big_meals/stamina-stirfry.html#ingredients","title":"Ingredients","text":"<p>Pork (thinly sliced) 250g Carrot 1/2 (about 80g) Chives 1 bunch (about 100g) Cabbage 1/8 head (about 100g) Garlic 2 cloves Sesame oil 1tbsp</p>"},{"location":"big_meals/stamina-stirfry.html#seasoning-for-pork","title":"Seasoning (for pork)","text":"<p>Salt 1/4 tsp Pepper a pinch Potato starch 1 tbsp</p>"},{"location":"big_meals/stamina-stirfry.html#sauce","title":"Sauce","text":"<p>Soy sauce 1.5tbsp Sake (or white wine) 1tbsp Mirin (or 1 tbsp white wine + 1 tsp sugat) 1tbsp Sugar 1tsp Oyster sauce 1tsp Grated garlic 1tsp Grated ginger 1/2 tsp</p>"},{"location":"big_meals/stamina-stirfry.html#instructions","title":"Instructions","text":"<ul> <li> <p>Cut the carrot into thin strips</p> </li> <li> <p>Roughly chop the cabbage</p> </li> <li> <p>Mince the garlic</p> </li> <li> <p>Cut the chives into 5 cm pieces</p> </li> <li> <p>Season the pork and massage well</p> </li> <li> <p>Heat sesame oil and cook the pork</p> </li> <li> <p>When it changes color, add garlic and carrot</p> </li> <li> <p>Add cabbage and cook until soft</p> </li> <li> <p>Add the sauce and cook it down</p> </li> <li> <p>Add chives and cook briefly</p> </li> </ul>"},{"location":"big_meals/tomato-sauce.html","title":"Tomato sauce creamy with vegetables","text":""},{"location":"big_meals/tomato-sauce.html#ingredients","title":"Ingredients","text":"<p>1-2 Tbs olive oil 200g onions, chopped  1-2 Tbsp garlic, minced 100-200g vegetables, minced (carrot and celery or courgette / sweet peppers)kkk 2 tins chopped tomatoes  6 sundried tomatoes, chopped  2 tsp sugar  1.5 tsp salt</p>"},{"location":"big_meals/tomato-sauce.html#method","title":"Method","text":"<p>Fry onions in olive oil until ever so slightly browned. Add garlic and veggies for 2 mins, stir a few times. Pour in tinned tomatoes and sundried tomatoes. Let simmer for 30-60mins. Transfer to a high speed blender and blend smooth. Season with 1.5 tsp salt and 2 tsp sugar.</p> <p>For creaminess add cashews and water 2:1 for the high speed blender step.</p>"},{"location":"big_meals/vietnamese-lemongrass-chicken.html","title":"Vietnamese lemongrass chicken","text":""},{"location":"big_meals/vietnamese-lemongrass-chicken.html#ingredients-per-2-servings-makes-2-meal-preps","title":"Ingredients per 2 servings (makes 2 meal preps)","text":"<p>1lb chicken thigh, skinless, boneless, raw</p>"},{"location":"big_meals/vietnamese-lemongrass-chicken.html#marinade","title":"Marinade","text":"<p>1 tbsp lemongrass</p> <p>2 garlic cloves</p> <p>1 tbsp shallot</p> <p>1 tbsp soy sauce</p> <p>1.5 tbsp oyster sauce</p> <p>1/2 tbsp fish sauce (phy quoc fish sauce brand)</p> <p>1/2 tbsp brown sugar</p> <p>1 tbsp honey</p> <p>salt and pepper to taste</p> <p>1 second cooking spray oil</p>"},{"location":"big_meals/vietnamese-lemongrass-chicken.html#side","title":"Side","text":"<p>1 carrot 1 Persian cucumber 1 cup of grated cabbage 1.5 cup cooked rice</p>"},{"location":"big_meals/vietnamese-lemongrass-chicken.html#sauce","title":"Sauce","text":"<p>1/2 tbsp lime juice</p> <p>2 tbsp sugar</p> <p>1 tbsp fish sauce (phy quoc fish sauce brand)</p> <p>2 garlic cloves</p> <p>2 tbsp water</p> <p>1 small red chili pepper (thai chili)</p>"},{"location":"big_meals/vietnamese-lemongrass-chicken.html#instructions","title":"Instructions","text":"<p>Thinly dice your shallot and thai chilis, slice your cucumbers into long strips, slice your carrots into small circles, and chop your cabbage into small pieces.</p> <p>In a bowl, mix your lemongrass, minced garlic, shallots, oyster sauce, soy sauce, fish sauce, brown sugar, honey, and chicken thighs and set aside for 30min-2hours in a fridge.</p> <p>In a pan on medium heat coated with spray oil, cook your chicken and season with salt and pepper to taste.</p> <p>In a small bowl, mix together lime juice, sugar, fish sauce, minced garlic, water and thai chilis to make your sauce.</p> <p>In a meal prep container, add half your cooked rice, half your carrots, half your cucumbers, half your cabbage, and half your lemongrass chicken and enjoy with half of the sauce!</p>"},{"location":"breakfast/baked-granola.html","title":"Baked granola","text":""},{"location":"breakfast/baked-granola.html#ingredients","title":"Ingredients","text":"<p>500g big oats 70g coconut oil 90g golden sirup 2 Tbs vanilla extract  2 tsp cinnamon  1/2 tsp salt </p> <p>Stir while pouring in the melted oil and sirup.</p> <p>Bake at 150-160C for 40 mins. Stir halfway through, after 20 mins. Bake in 2cm layer.</p>"},{"location":"breakfast/courgette-fritters.html","title":"Courgette fritters","text":""},{"location":"breakfast/courgette-fritters.html#ingredients","title":"Ingredients","text":"<p>500g courgettes, grated 2tsp fine salt 2tsp onion powder  2tsp onion granules  1 heaped Tbsp gram flour + 3Tbsp warm water (replaces 1 eggs) 30g potato starch 25g oat flour</p>"},{"location":"breakfast/courgette-fritters.html#method","title":"Method","text":"<p>Grate courgettes. Mix w 2 tsp fine salt. Transfer mix to fine sieve and place sieve over bowl. Let liquid drain, push liquid out w a large spoon and applying pressure. Once most liquid has drained, tip out liquid and put grated and salted courgettes back in the bowl.</p> <p>Add gram egg. Mix well. Mix onion powder, granules, potato starch and  oat flour. Add the dry mix to the bowl. Mix some more and let rest for 15 mins.</p> <p>Fry in small portions (slightly heaped Tbsp) from both sides medium heat</p>"},{"location":"breakfast/pancakes.html","title":"\ud83e\udd5e Pancakes thin / thick","text":""},{"location":"breakfast/pancakes.html#ingredients","title":"\ud83d\uded2 Ingredients","text":"<p>210g white flour 70g wholegrain flour (optional, can be replaced w 80g white flour) 1.5 / 2.5 tsp baking powder (thin / thick) 1 tsp vanilla extract  28g melted butter / neutral oil (if using wholegrain flour, otherwise optional) 60g sugar 470 / 600ml (soy) milk (thick / thin)</p>"},{"location":"breakfast/pancakes.html#method","title":"\ud83d\udc68\u200d\ud83c\udf73 Method","text":"<p>Mix dry ingredients. Add 330ml soy milk and mix, this is it avoid clumps. Add remaining milk (140ml for thick, 270ml for thin). Add vanilla extract and melted butter / oil. Stir carefully. Let batter rest for 5-10 mins. </p> <p>Heat frying pan. Add thin coating of oil w silicon brush. Add pancake batter and tilt the pan to make thinner pancakes.</p>"},{"location":"breakfast/porridge-bread.html","title":"Porridge bread","text":""},{"location":"breakfast/porridge-bread.html#ingredients","title":"Ingredients","text":"<p>400g rolled oats</p> <p>2 tsp bicarbonate of soda</p> <p>1/2 tsp fine salt</p> <p>500g thick skyr or Greek yoghurt</p> <p>220ml milk</p> <p>1 egg, beaten</p> <p>Mixed seeds, to top</p>"},{"location":"breakfast/porridge-bread.html#instructions","title":"Instructions","text":"<ul> <li> <p>Preheat the oven to 200\u00b0C fan and grease and line a 1lb loaf tin.</p> </li> <li> <p>Add the oats, bicarbonate of soda and salt to a large bowl and mix together.</p> </li> <li> <p>Add the yoghurt, milk and egg, then mix really well until fully combined.</p> </li> <li> <p>Tip into the loaf tin, pack down and smooth the top with the back of a spoon and score a line down the middle with a knife. Scatter over the seeds and gently press them in with your hands.</p> </li> <li> <p>Bake for 45 minutes, leave to cool for 5 minutes, then carefully remove from the tin (paper still on) and place directly onto the oven shelf for a final 5 minutes to crisp up the crust.</p> </li> </ul>"},{"location":"breakfast/potato-fritters.html","title":"Potato Fritters","text":""},{"location":"breakfast/potato-fritters.html#ingredients","title":"Ingredients","text":"<p>750g potatoes, grated 2tsp fine salt 2tsp onion powder  2tsp onion granules  3 heaped Tbsp gram flour + 9Tbsp warm water (replaces 3 eggs) 35g oat flour</p>"},{"location":"breakfast/potato-fritters.html#method","title":"Method","text":"<p>Grate potatoes. Mix w 2 tsp fine salt. Transfer mix to fine sieve and place sieve over bowl. Let liquid drain, push liquid out w a large spoon and applying pressure. Once most liquid has drained, tip out liquid and put grated and salted potatoes back in the bowl.</p> <p>Add onion powder and granules plus gram eggs. Mix well. Add oat flour. Mix some more and let rest for 15 mins. Fry in small portions (slightly heaped Tbsp) from both sides medium heat</p>"},{"location":"breakfast/tofu-oat-pancakes.html","title":"Tofu oat pancakes","text":"<p>Makes 12 small pancakes / 4 servings</p>"},{"location":"breakfast/tofu-oat-pancakes.html#ingredients","title":"Ingredients","text":"<p>400g / 14oz firm tofu 160g / 1 3/4 cups rolled oats 150ml /2/3 cup plant-based milk 2 tbsp maple syrup 1 tsp baking powder Pinch of salt</p>"},{"location":"breakfast/tofu-oat-pancakes.html#method","title":"Method","text":"<ol> <li> <p>Add all ingredients to a high-speed blender powerful enough to process  oats</p> </li> <li> <p>Blend on low speed until combined.</p> </li> <li> <p>Increase to high speed and blend briefly until no large particles remain. The batter should be thick enough to hold on a spatula but fluid enough to spread slightly -- like thick pancake batter, not thin cr\u00eape batter.</p> </li> <li> <p>Heat a non-stick pan over medium-high heat. Add a small amount of oil or butter of your choice.</p> </li> <li> <p>Scoop the batter into the pan -- about 60ml / 1/4 cup per pancake -- and gently shape into a circle.</p> </li> <li> <p>Cook for 2 minutes until the surface looks dry and set, then flip. Cook for a further 1 minute until fully cooked through.</p> </li> <li> <p>Repeat with remaining batter.</p> </li> <li> <p>Serve with maple syrup, yoghurt and fresh fruit of your choice.</p> </li> </ol> <p>Enjoy!</p>"},{"location":"breakfast/tofu-oat-pancakes.html#nutrition-per-serving-3-pancakes","title":"Nutrition per serving (3 pancakes)","text":"<p>Calories: 260 kcal Protein: 15g Fat: 7.5g Carbs: 35g Fiber: 4.3g</p>"},{"location":"breakfast/wunderbroed.html","title":"Wunderbroed Scandinavian Bread","text":""},{"location":"breakfast/wunderbroed.html#ingredients","title":"Ingredients","text":"<p>Psyllium husk</p> <p>Oats</p> <p>Gluten free bread</p>"},{"location":"salad/cucumber-chicken-salad.html","title":"Cucumber chicken salad","text":""},{"location":"salad/cucumber-chicken-salad.html#key-ingredients","title":"Key ingredients","text":"<p>Chicken. I call for poaching boneless, skinless chicken breasts in this recipe. You\u2019ll dice or shred the chicken into bite-size pieces.</p> <p>Cucumber. You can use Persian cucumbers or an English cucumber here, either works well.  Rice vinegar. Adds a tangy bite to the salad. </p> <p>Toasted sesame seeds. I swear by the containers of toasted sesame seeds that I find at Lotte Market and other Asian grocery stores. If you can\u2019t find those, you can toast your own seeds.</p>"},{"location":"salad/cucumber-chicken-salad.html#how-to-make","title":"How to make","text":"<ul> <li> <p>Poach the chicken and chop your cucumber. Bring a pot of lightly salted water to a boil, then add the chicken and reduce the temperature to low until the chicken reaches an internal temperature of 165 degrees. While the chicken cools, chop the cucumbers. Shred or dice the chicken to get bite-size pieces.</p> </li> <li> <p>Make the dressing. Mix rice wine vinegar, toasted sesame seeds, salt, pepper, sesame oil, and sugar together in a large bowl.</p> </li> <li> <p>Finish the salad and serve. Toss the chicken and cucumbers with the dressing. To serve, scoop the salad onto mixed greens, and garnish with thinly sliced scallions or chopped cilantro. It also makes a great sandwich on sourdough bread or a baguette, just drain the dressing before assembling so the sandwich doesn\u2019t get too soggy.</p> </li> </ul>"},{"location":"salad/cucumber-chicken-salad.html#ingredients","title":"Ingredients","text":"<p>Boneless, skinless chicken chicken breasts (about 1 pound total)</p> <p>2 teaspoons kosher salt, divided, plus more as needed</p> <p>2 Persian cucumbers or 1 large English cucumber</p> <p>1/4 cup rice vinegar</p> <p>1 tablespoon toasted sesame seeds</p> <p>1 teaspoon granulated sugar</p> <p>1/2 teaspoon toasted sesame oil</p> <p>Optional: Chopped scallions or fresh cilantro, for garnish</p>"},{"location":"salad/cucumber-chicken-salad.html#instructions","title":"Instructions","text":"<p>Place 2 boneless, skinless chicken breasts in a large saucepan and add enough water to cover by about 2 inches. Add 1 teaspoon of the kosher salt, and bring to a boil over high heat. Reduce the heat to low and simmer until the chicken is cooked through and registers at least 165\u00baF in the thickest part, 8 to 10 minutes.</p> <p>Transfer the chicken to a cutting board. Let cool for about 5 minutes. Meanwhile, dice 2 Persian cucumbers or 1 large English cucumber (about 3 cups). (No need to peel first or remove the seeds, but feel free to do so if you prefer.) Place the remaining 1 teaspoon kosher salt, 1/4 cup rice vinegar, 1 tablespoon toasted sesame seeds, 1 teaspoon coarsely ground black pepper, 1 teaspoon granulated sugar, and 1/2 teaspoon toasted sesame oil in a large bowl and whisk until the sugar and salt are dissolved.</p> <p>Dice or shred the chicken into bite-size pieces. Add the chicken and cucumbers to the dressing and toss to combine. Taste and season with more kosher salt as needed. Garnish with chopped scallions or fresh cilantro if desired.</p>"},{"location":"salad/cucumber-chicken-salad.html#recipe-notes","title":"Recipe notes","text":"<p>Substitutions: Use whatever kind of cucumber you like. I prefer Persian or English cucumbers because their seeds are small enough to include, but if you use a cuke with heftier seeds, use a spoon to remove them before dicing.</p> <p>Make ahead: The salad can be made up to 4 days ahead and refrigerated in an airtight container. Stir before serving.</p> <p>Storage: Refrigerate in an airtight container for up to 5 days.</p>"},{"location":"salad/maple-sesame-tofu-salad.html","title":"Maple sesame tofu crispy rice salad","text":""},{"location":"salad/maple-sesame-tofu-salad.html#ingredients","title":"Ingredients","text":"<p>200g cooked rice, cooled (about 1 1/2 cups)</p> <p>2 tsp olive oil</p> <p>1 tsp low sodium soy sauce</p> <p>Crispy Maple Sesame Tofu:</p> <p>300g firm tofu</p> <p>1 tbsp Canadian maple syrup</p> <p>1 tsp soy sauce</p> <p>1 tbsp corn starch</p> <p>1 tbsp sesame seeds</p> <p>2 tsp olive oil</p> <p>Other:</p> <p>200g cooked edamame 1 medium carrot, julienned 1 medium cucumber, thinly sliced 1/2 small red onion, thinly sliced 1 avocado, sliced 1 big handful fresh mint, chopped 1 big handful fresh coriander, chopped</p> <p>Dressing:</p> <p>2 tbsp smooth peanut butter</p> <p>Juice from 1/2 lime</p> <p>1 tbsp Canadian maple syrup</p> <p>1 tbsp soy sauce</p> <p>Preheat the oven to 200\u00b0C. Line two bakking trays with baking paper.</p> <p>Add the rice to a tray with the olive oil and soy sauce. Toss until evenly coated and spread the rice out in an even layer. Bake for 15-20 minutes (on the lower rack in the oven), until lightly golden - avoid overcooking.</p> <p>Dice the tofu into cubes and add to a bowl with the maple syrup, olive oil, soy sauce, corn starch and sesame seeds. Toss until well coated. Spread the tofu out on the second tray and bake for 25 to 30 minutes, until golden and crisp.</p> <p>Whisk the peanut butter, lime juice, maple syrup and soy sauce together in a small bowl until smooth. You can adjust the texture by adding more peanut butter to thicken or  some water to thin.</p>"},{"location":"salad/mustard-dressing.html","title":"Mayonnaise Mustard Dressing","text":""},{"location":"salad/mustard-dressing.html#ingredients","title":"Ingredients","text":"<p>100g mayonnaise, vegan Hellmann\u2019s</p> <p>100g / ml soya milk</p> <p>10g Dijon mustard, Maille</p> <p>8g salt</p>"},{"location":"salad/mustard-dressing.html#method","title":"Method","text":"<p>Put all ingredients into a jar with a lid and shake or mix them in a bowl / glass with a fork.</p>"},{"location":"salad/peanutty-chicken-salad.html","title":"Peanutty chicken salad","text":"<p>Serves 1.</p>"},{"location":"salad/peanutty-chicken-salad.html#for-the-dressing","title":"For the dressing","text":"<p>1 tbsp soy sauce</p> <p>1 tsp garlic + ginger paste (lazy hack, use fresh if you like)</p> <p>1tsp sriracha</p> <p>15g peanut buter</p> <p>juice of 1/2 large lime, or 1 small</p>"},{"location":"salad/peanutty-chicken-salad.html#for-the-salad","title":"For the salad","text":"<p>1 small carrot, julienned</p> <p>approx. 10cm cucumber, cored and finely sliced</p> <p>handful of mint leaves</p> <p>handful of coriander leaves</p> <p>75g frozen edamame, thawed</p> <p>1/2 red chilli, sliced</p> <p>1 cooked chicken brest, shredded</p> <p>approx. 8g toasted peanuts, roughly chopped</p> <p>1 tsp sesame seeds</p>"},{"location":"salad/sesame-miso-tuna-salad.html","title":"Sesame Miso Tuna Salad (For Tinned Tuna)","text":"<p>If you are looking to elevate a standard tin of tuna, you can make a delicious, high-protein salad or sandwich filling.</p> <p>The Sauce: Whisk together 1 tbsp miso paste, 1 tbsp rice vinegar, 1/2 tbsp honey, and 1/2 tbsp sesame oil.</p> <p>The Mix-in: Toss your drained tinned tuna with diced cucumber, celery, carrots, and green onions.</p> <p>Finish: Pour the sauce over the tuna, mix well, and top generously with extra sesame seeds.</p>"},{"location":"savoury/cajun-kidney-beans.html","title":"Cajun kidney beans","text":""},{"location":"savoury/cajun-kidney-beans.html#ingredients","title":"Ingredients","text":"<p>1 Tbs oil 400g minced red onions 30g minced garlic 2 Tbs Cajun spice mix (M&amp;S) 400g finely minced green peppers 400g finely minced celery (peeled on the outside) 10 tins Kidney beans (drained and rinsed) 2 bay leaves 450ml veg broth 3.5 tsp smoked salt / salt 2 tsp dark brown sugar 3 Tbs lime juice</p>"},{"location":"savoury/cajun-kidney-beans.html#method","title":"Method","text":"<ul> <li> <p>Fry onions until browned</p> </li> <li> <p>Add garlic and spices and fry some more</p> </li> <li> <p>Add everything to the slow cooker cook on high (hours) or on low (hours)</p> </li> <li> <p>Mash about half the kidney beans, just inside the slow cooker.</p> </li> </ul>"},{"location":"savoury/chickpea-cheese-crackkers.html","title":"Chickpea and Cheese Crackers","text":"<p>Tags: Vegan, Grain-free, High protein)</p> <p>Prep time: 20 minutes Cook time: 20 minutes Total time: 40 minutes</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#ingredients","title":"Ingredients","text":"<p>1 cup cooked and drained chickpeas</p> <p>1/2 cup grated cheese (Parmesan or Cheddar)</p> <p>1/2 teaspoon garlic powder</p> <p>1 tablespoon extra virgin olive oil</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#directions","title":"Directions","text":""},{"location":"savoury/chickpea-cheese-crackkers.html#preheat-the-oven","title":"Preheat the Oven:","text":"<p>Preheat your oven to 375\u00b0F (190\u00b0C). Line a baking sheet with parchment paper.</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#prepare-the-dough","title":"Prepare the Dough:","text":"<p>In a food processor, combine the chickpeas, grated cheese, garlic powder, and olive oil. Process until the mixture forms a cohesive dough. If the dough is too dry, add a small amount of water, one teaspoon at a time, until it comes together.</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#shape-the-crackers","title":"Shape the Crackers:","text":"<p>Transfer the dough onto a clean surface. Roll it out to about 1/4-inch thickness. Use a knife or small cookie cutter to cut into desired cracker shapes.</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#bake","title":"Bake:","text":"<p>Place the shaped dough pieces onto the prepared baking sheet. Bake for 15\u201320 minutes or until the crackers are golden and crisp around the edges.</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#cool-and-serve","title":"Cool and Serve:","text":"<p>Let the crackers cool completely on a wire rack before serving. Store any leftovers in an airtight container.</p>"},{"location":"savoury/chickpea-cheese-crackkers.html#nutritional-information","title":"Nutritional information","text":"<p>Calories: Approximately 110 kcal per serving | Servings: 4 servings</p>"},{"location":"savoury/cilantro-lime-rice.html","title":"Cilantro lime rice","text":"<p>Note</p> <p>test</p> <p>3--5 servings</p>"},{"location":"savoury/cilantro-lime-rice.html#ingredients","title":"Ingredients","text":"<ul> <li>cooked rice (about 2 rice-cooker cups)</li> <li>a handful of edamame</li> <li>a small handful of cilantro, chopped</li> <li>2 green onions, chopped</li> <li>juice of 1/2 line</li> <li>2-3 tbsp olive oil</li> <li>salt to taste</li> </ul>"},{"location":"savoury/kidney-bean-leberwurst-vegan.html","title":"Kidney Bean Smoked Tofu Leberwurst Vegan","text":""},{"location":"savoury/kidney-bean-leberwurst-vegan.html#ingredients","title":"Ingredients","text":"<p>1 can kidney beans, 240g drained weight</p> <p>150g smoked tofu</p> <p>1 onion, small</p> <p>2 tsp marjoram</p> <p>1 tsp mustard</p> <p>1 tsp smoked salt, alternatively regular salt</p> <p>1/2 tsp pepper</p> <p>2 tbsp vegetable oil, e.g. rapeseed oil</p>"},{"location":"savoury/kidney-bean-leberwurst-vegan.html#preparation","title":"Preparation","text":"<p>Finely dice the onion and saut'e in a pan with a dash of vegetable oil at medium temperature for  a few minutes. Add marjoram and sweat briefly. Remove from the heat and let cool down a bit.</p> <p>Drain the beans well. Roughly crumble the tofu. Mix with all the other ingredients in a food processor or with the help of a hand blender until the vegan liver sausage has the desired consistency. If necessary, add a few drops of water in the course of this.</p>"},{"location":"savoury/tahini-hummus.html","title":"Tahini-Hummus","text":""},{"location":"savoury/tahini-hummus.html#ingredients","title":"Ingredients","text":"<p>1 medium-large clove of garlic 110ml water 45ml lemon juice 250g tahini 480g chickpeas 1.5 tsp salt</p>"},{"location":"savoury/tahini-hummus.html#method","title":"Method","text":"<p>Pur\u00e9e all but the chickpeas first. Then add half the chickpeas and puree until smooth. Add the second half of chickpeas and puree until smooth or leave some coarseness.</p>"},{"location":"savoury/tahini-sauce.html","title":"Tahini sauce","text":"<p>For Lebanese recipes always use the light-coloured version and not the whole dark tahini.</p>"},{"location":"savoury/tahini-sauce.html#yield","title":"Yield","text":"<p>Makes 250ml.</p>"},{"location":"savoury/tahini-sauce.html#ingredients","title":"Ingredients","text":"<p>100g tahini 2 tbsp lemon juice 1 clove garlic, crushed 1/2 tsp salt About 100ml cold water</p>"},{"location":"savoury/tahini-sauce.html#preparation-time","title":"Preparation time","text":"<p>5 minutes</p>"},{"location":"savoury/tikka-masala-lentils.html","title":"Tikka masala lentils","text":""},{"location":"savoury/tikka-masala-lentils.html#ingredients","title":"Ingredients","text":"<p>1 Tbsp oil 400g minced onions 25g minced garlic 2 blocks of taj crushed ginger 6 tsp tikka masala spice mix (M&amp;S) 400g chopped tomatoes (1 tin) 3 cups dry brown lentils washed 8 cups water &amp; veg broth mix 8 tsp pur\u00e9ed mango Salt Sugar</p>"},{"location":"savoury/tikka-masala-lentils.html#method","title":"Method","text":"<ul> <li> <p>Fry onions until golden. Add garlic for a 30s, then add ginger for 30s then add spices for another 30s.</p> </li> <li> <p>Add tomatoes and mash.</p> </li> <li> <p>Add a ingredients to a slow cooker and cook on high (hours) or on low (hours)</p> </li> </ul>"},{"location":"savoury/vegan-mett.html","title":"Vegan Mett","text":""},{"location":"savoury/vegan-mett.html#ingredients","title":"Ingredients","text":"<p>100g rice cakes</p> <p>250-300ml water</p> <p>1/2-1 white onion</p> <p>50g tomato paste</p> <p>Salt &amp; pepper</p> <p>2 sprigs parsley</p> <p>4 white bread rolls</p>"},{"location":"savoury/vegan-mett.html#preparation","title":"Preparation","text":"<p>Crumble the rice cakes in a bowl with your fingers.</p> <p>Add the water and gradually fold in with a fork so that the water can distribute well. Let soak.</p> <p>Cut off the ends of the onions, remove the peel and dice the onion.</p> <p>Add diced onion and tomato paste to the soaked rice cake and fold in with a fork and distribute well.</p> <p>Season well with salt and pepper. Then let rest in the refrigerator for a few hours for best results.</p>"},{"location":"soup/black-bean-soup.html","title":"Slow cooker black bean soup","text":""},{"location":"soup/black-bean-soup.html#ingredients","title":"Ingredients","text":"<p>1 pound dried black beans</p> <p>1 medium onion, diced</p> <p>1 medium red bell pepper, cored, seeded, and diced</p> <p>3 cloves garlic, minced</p> <p>6 cups low-sodium vegetable broth</p> <p>1 1/2 tablespoons chili powder</p> <p>1 tablespoon ground cumin</p> <p>2 teaspoons kosher salt</p> <p>2 bay leaves</p> <p>1/2 teaspoon freshly ground black pepper</p>"},{"location":"soup/black-bean-soup.html#optional-toppings","title":"Optional toppings","text":"<p>Fresh cilantro leaves and stems</p> <p>Chopped avocado</p> <p>Greek yogurt</p>"},{"location":"soup/black-bean-soup.html#instructions","title":"Instructions","text":"<ul> <li> <p>Place the black beans, onion, bell pepper, garlic, broth, chili powder, cumin, bay leaves, salt, and pepper in a 6-quart or larger slow cooker and stir to combine. Cover and cook on the LOW setting until the beans are tender, 8 to 10 hours.</p> </li> <li> <p>Remove the bay leaves and serve with Greek yogurt, fresh cilantro, or chopped avocado if desired.</p> </li> </ul>"},{"location":"soup/black-bean-soup.html#recipe-notes","title":"Recipe notes","text":"<p>Storage: Leftovers can be stored in an airtight container in the refrigerator for up to 5 days or in the freezer for up to 3 months.</p>"},{"location":"soup/black-bean-soup.html#nutritional-info","title":"Nutritional info","text":"Per serving, based on 8 servings. (% daily value) Calories 215 Fat 1.3 g (2.1%) Saturated 0.3 g (1.4%) Carbs 39.5 g (13.2%) Fiber 10.1 g (40.5%) Sugars 2.6 g Protein 13.0 g (26.1%) Sodium 546.2 mg (22.8%)"},{"location":"soup/carrot-soup.html","title":"Carrot soup (creamy Thai)","text":""},{"location":"soup/carrot-soup.html#ingredients","title":"Ingredients","text":"<p>1 Tbsp neutral oil</p> <p>250g onions, chopped</p> <p>1.5 Tbsp garlic, minced</p> <p>2 Tbsp ginger, minced</p> <p>650g carrots 1.5cm</p> <p>350g parsnip (or more carrot)</p> <p>1l broth, veg or (fake) chicken</p> <p>2 Tbsp soya sauce / tamari</p> <p>2 Tbsp vegetarian fish sauce</p> <p>0.5-1 Tbs sriracha </p> <p>50g creamed coconut (optional)</p> <p>250ml of orange juice</p> <p>2 Tbsp sugar</p>"},{"location":"soup/carrot-soup.html#method","title":"Method","text":"<p>Fry the onions until golden. Add garlic and ginger and fry for another minute. Add carrots and broth. Bring to a boil and simmer for 8 mins. Add parsnip cubes and simmer for another 18 minutes. Add sauces and sugar, blend smooth in high speed blender. Pour back into the pot and stir in orange juice.</p>"},{"location":"soup/french-lentil-soup.html","title":"French lentil soup smokey","text":"<p>Stove top or slow cooker </p>"},{"location":"soup/french-lentil-soup.html#ingredients","title":"Ingredients","text":"<p>1.5 Tbs olive oil</p> <p>450g minced (red) onions</p> <p>6 cloves minced garlic</p> <p>2 Tbsp thyme</p> <p>2 Tbsp smoked paprika</p> <p>2 Tbsp tomato pur\u00e9e</p> <p>1.5 tsp Dijon mustard </p> <p>600g carrots in thick slices</p> <p>3 cups French lentils (puy / green / brown)</p> <p>3 cups vegetable or (fake) chicken stock</p> <p>5 cups water</p> <p>2 bay leaves</p> <p>1.5 tsp salt</p> <p>2 Tbsp lemon juice</p>"},{"location":"soup/french-lentil-soup.html#method","title":"Method","text":"<p>Fry the onions until golden. Add the garlic and fry for a minute. Add thyme, smoked paprika, tomato pur\u00e9e and Dijon mustard, fry for another minute. Add vegetables stock and stir to dissolve residue stuck to the bottom of the pot. Transfer everything to the slow cooker. Add carrots, washed lentils, water, bay leaves and salt. Cook on high for 4h. Stove top method (simmering) requires 1h approximately.</p> <p>Add lemon juice and season to taste with more salt.</p>"},{"location":"soup/lemony-lentil.html","title":"Lemony Lentil &amp; Chard Soup","text":"<p>This satisfying lemony bowlful was inspired by the lentil soup served at the now-closed Lebanese restaurant La Shish in West Bloomfield, Michigan. It keeps well but will thicken, so you may want to thin it with a bit of water or broth when reheating. Serve with warm whole-wheat pita.</p>"},{"location":"soup/lemony-lentil.html#method","title":"Method","text":"<p>Active Time: 30 mins</p> <p>Total Time: 55 mins</p> <p>Servings: 6 </p>"},{"location":"soup/lemony-lentil.html#nutrition-profile","title":"Nutrition Profile","text":"<p>Mediterranean Diet Dairy-Free Soy-Free High-Fiber Vegan Vegetarian High-Protein Egg-Free Gluten-Free Low-Calorie</p>"},{"location":"soup/lemony-lentil.html#ingredients","title":"Ingredients","text":"<p>3 tablespoons extra-virgin olive oil, plus more for serving</p> <p>1 large onion, diced</p> <p>1 bunch chard</p> <p>4 cloves garlic, finely chopped</p> <p>1 tablespoon ground cumin</p> <p>\u00bd teaspoon Aleppo pepper, plus more for serving</p> <p>8 cups water</p> <p>1 pound red lentils, picked over and rinsed</p> <p>1 \u00bd teaspoons salt</p>"},{"location":"sweet/frangipane.html","title":"Frangipane (Almond Cream)","text":"<p>Frangipane, a staple of classic French pastry, is a creamy, sweet, almondy filling that\u2019s surprisingly easy to make and has many uses. This frangipane recipe uses simple ingredients like butter, sugar, eggs, and almond flour to ensure the almond flavor shines through. Spread frangipane into a tart shell, pipe it into croissant dough to make a decadent breakfast pastry, or spread it onto brioche to make Bostock.</p>"},{"location":"sweet/frangipane.html#preparation","title":"Preparation","text":"<p>5 mins</p>"},{"location":"sweet/frangipane.html#total","title":"Total","text":"<p>5 mins</p>"},{"location":"sweet/frangipane.html#yield","title":"Yield","text":"<p>about 1 3/4 cups</p> <p>Frangipane (Almond Cream)</p>"},{"location":"sweet/frangipane.html#ingredients","title":"Ingredients","text":"<p>6 tablespoons (85g) unsalted butter, at room temperature 1/2 cup (99g) granulated sugar 1/4 teaspoon table salt 1 cup (96g) King Arthur Almond Flour 3 tablespoons (23g) King Arthur Unbleached All-Purpose Flour or King Arthur Gluten-Free Measure for Measure Flour 1 large egg, at room temperature 2 teaspoons almond emulsion or almond extract</p>"},{"location":"sweet/frangipane.html#instructions","title":"Instructions","text":"<p>In a medium bowl or the bowl of a stand mixer, beat together the butter, sugar, and salt until pale and fluffy, about 1 minute on medium speed.</p> <p>Stir in the flours, egg, and almond flavoring. Mix until just combined.</p> <p>Use the frangipane as desired: fill tart shells, pipe into croissant dough, top slices of Bostock, or come up with your own way to use this flavorful, nutty filling. Bake the frangipane as directed in your recipe or until it\u2019s golden brown and smells nutty.</p> <p>Store leftover unbaked frangipane in the refrigerator, covered, for up to 1 week or freeze for up to 2 months.</p>"},{"location":"sweet/peanut-butter-cookie-dough-bites.html","title":"Peanut butter cookie dough bites","text":""},{"location":"sweet/peanut-butter-cookie-dough-bites.html#ingredients","title":"Ingredients","text":"<p>150g gluten-free rolled oats</p> <p>2 tablespoons coconut oil</p> <p>2 tablespoons smooth peanut butter, almond butter or</p> <p>sunflower seed butter</p> <p>60ml pure maple syrup or other liquid sweetener</p> <p>1 teaspoon pure vanilla extract</p> <p>60g almond flour or almond meal</p> <p>\u00bc teaspoon fine-grain sea salt</p> <p>2 tablespoons mini dark chocolate chips or chopped dark</p> <p>chocolate</p>"},{"location":"sweet/peanut-butter-cookie-dough-bites.html#yield","title":"Yield","text":"<p>Makes 14 small bites</p>"},{"location":"sweet/peanut-butter-cookie-dough-bites.html#preparation","title":"Preparation","text":"<p>PREP TIME: 15 minutes</p> <p>CHILL TIME: 10 minutes</p>"},{"location":"sweet/peanut-butter-cookie-dough-bites.html#allergy-info","title":"Allergy info","text":"<p>gluten-free, raw/no-bake, soy-free option, nut-free option, refined sugar-free</p>"},{"location":"sweet/peanut-butter-cookie-dough-bites.html#instructions","title":"Instructions","text":"<p>In a high-speed blender, blend the oats until a fine flour forms. Set aside.</p> <p>In a large bowl, combine the oil, peanut butter, maple syrup, and vanilla and beat with a hand mixer until smooth. Add the almond flour, oat flour, and salt and beat again until combined. Fold in the chocolate chips.</p> <p>Roll the dough intc small balls (about 1 tablespoon of dough each). If chocolate chips fall to the bottom of the bowl, press them back into the dough when rolling. Place the fihished bites on a plate lined with parchment paper.</p> <p>Freeze the bites for 5 to 10 minutes, or until firm. Store the bites in the freezer in a freezer bag for quick and easy snacks.</p>"},{"location":"sweet/peanut-butter-cookie-dough-bites.html#tips","title":"Tips","text":"<p>For a nut-free version, simply swap sunflower seed butter for the peanut butter and more oat</p> <p>flour for the almond flour (add a splash of non-dairy milk if the dough is a bit dry). Both versions work just fine.</p> <p>For a soy-free option, use soy-free chocolate chips (such as Enjoy Life brand)</p> <p>[Liddon, Oh She Glows, S. 234]</p>"}]}